import pyotp
from datetime import datetime, timedelta

class TOTPAuthenticator:
    def __init__(self):
        self.secrets = {}

    def generate_secret(self, user_id):
        secret = pyotp.random_base32()
        self.secrets[user_id] = secret
        return secret

    def create_qr_code(self, user_id):
        secret = self.secrets[user_id]
        qr_code = pyotp.totp.TOTP(secret).provisioning_uri(user_id)
        return qr_code

    def validate_totp(self, user_id, totp):
        secret = self.secrets[user_id]
        expected_value = pyotp.TOTP(secret).at(datetime.now())
        if totp == expected_value:
            return True
        else:
            return False